```javascript
import React, { useState, useEffect } from 'react';
import { View, Text, StyleSheet } from 'react-native';
import MapView, { Marker } from 'react-native-maps';
import { firebase } from '@firebase/app';
import '@firebase/database';

const RealtimeTracking = () => {
  const [courierLocation, setCourierLocation] = useState(null);

  useEffect(() => {
    const courierRef = firebase.database().ref('courier_location');
    courierRef.on('value', (snapshot) => {
      const data = snapshot.val();
      setCourierLocation({latitude: data.latitude, longitude: data.longitude});
    });
    return () => courierRef.off();
  }, []);

  if (!courierLocation) {
    return <Text>Loading...</Text>;
  }

  return (
    <View style={styles.container}>
      <MapView
        style={styles.map}
        initialRegion={{
          latitude: courierLocation.latitude,
          longitude: courierLocation.longitude,
          latitudeDelta: 0.0922,
          longitudeDelta: 0.0421,
        }}
      >
        <Marker
          coordinate={{latitude: courierLocation.latitude, longitude: courierLocation.longitude}}
          title={"Courier Location"}
        />
      </MapView>
    </View>
  );
}

const styles = StyleSheet.create({
  container: {
    ...StyleSheet.absoluteFillObject,
    justifyContent: 'flex-end',
    alignItems: 'center',
  },
  map: {
    ...StyleSheet.absoluteFillObject,
  },
});

export default RealtimeTracking;
```

In this code, we first import the required modules and initialize the state of the courier's location. We then set up a `useEffect` hook that listens to changes in the courier's location in real-time using Firebase Realtime Database. Whenever the location changes, we update the marker's coordinates to show the courier's latest location.

If the courier's location has not yet been received, we return a loading message to avoid rendering errors.

The example code above is a basic implementation of real-time tracking using React Native with Firebase Realtime Database and MapView. However, it can be customized as per the specific needs and requirements of the motorbike delivery system.

